import static org.junit.jupiter.api.Assertions.*;
import org.apache.commons.csv.CSVFormat;
import org.junit.jupiter.api.Test;

public class CSVFormatTest {

    @Test
    void testGetEscapeCharacterWhenNull() {
        CSVFormat format = CSVFormat.DEFAULT.withEscape((Character) null);
        assertNull(format.getEscapeCharacter());
    }

    @Test
    void testGetEscapeCharacterWhenSet() {
        Character escapeChar = '\\';
        CSVFormat format = CSVFormat.DEFAULT.withEscape(escapeChar);
        assertEquals(escapeChar, format.getEscapeCharacter());
    }

    @Test
    void testGetEscapeCharacterFromPredefinedFormats() {
        assertNull(CSVFormat.DEFAULT.getEscapeCharacter());
        assertEquals('\\', CSVFormat.INFORMIX_UNLOAD.getEscapeCharacter());
        assertNull(CSVFormat.INFORMIX_UNLOAD_CSV.getEscapeCharacter());
        assertEquals('\\', CSVFormat.MYSQL.getEscapeCharacter());
        assertEquals('"', CSVFormat.POSTGRESQL_CSV.getEscapeCharacter());
        assertEquals('"', CSVFormat.POSTGRESQL_TEXT.getEscapeCharacter());
        assertNull(CSVFormat.RFC4180.getEscapeCharacter());
        assertNull(CSVFormat.TDF.getEscapeCharacter());
    }
}
